import{_ as i,o as a,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Wiki","description":"","frontmatter":{},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/kodi/wiki.md","filePath":"microcontrollers-and-socs/raspberry-pi/kodi/wiki.md"}'),s={name:"microcontrollers-and-socs/raspberry-pi/kodi/wiki.md"};function o(l,e,n,h,p,d){return a(),r("div",null,[...e[0]||(e[0]=[t(`<h1 id="wiki" tabindex="-1">Wiki <a class="header-anchor" href="#wiki" aria-label="Permalink to &quot;Wiki&quot;">​</a></h1><p><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1" target="_blank" rel="noreferrer">https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1</a></p><table tabindex="0"><thead><tr><th><a href="https://kodi.wiki/view/Main_Page" target="_blank" rel="noreferrer"><img src="https://kodi.wiki/images/a/aa/Home_icon_grey.png" alt="Home icon grey.png"></a></th><th></th><th></th><th><img src="https://kodi.wiki/images/5/5f/TriangleArrow-Right.png" alt="▶"> <a href="https://kodi.wiki/view/Raspberry_Pi" target="_blank" rel="noreferrer">Raspberry Pi</a></th><th><img src="https://kodi.wiki/images/5/5f/TriangleArrow-Right.png" alt="▶"> HOW-TO:Install Kodi on Raspberry Pi</th></tr></thead></table><p>The basic hardware you will need is</p><ul><li>the R-Pi board itself</li><li>a power supply (Micro-USB, 5V, upto 2500 mA)</li><li>a (micro)SDHC memory card to install the software. (Because video decoding is more resource-intensive than many other operations, it may be more important to have a fast/high quality memory card for Kodi than for other uses.)</li></ul><br><h2 id="contents" tabindex="-1">Contents <a href="#mw-toc-heading" id="mw-toc-heading"></a> <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents &lt;a href=&quot;#mw-toc-heading&quot; id=&quot;mw-toc-heading&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><ul><li><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1#Basic_options" target="_blank" rel="noreferrer">1Basic options</a></li><li><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1#Specific_install_guides" target="_blank" rel="noreferrer">2Specific install guides</a><ul><li><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1#Raspberry_Pi_OS" target="_blank" rel="noreferrer">2.1Raspberry Pi OS</a></li><li><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1#RetroPie" target="_blank" rel="noreferrer">2.2RetroPie</a></li></ul></li><li><a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi?https=1#Compiling_Kodi" target="_blank" rel="noreferrer">3Compiling Kodi</a></li></ul><h3 id="basic-options" tabindex="-1">Basic options <a class="header-anchor" href="#basic-options" aria-label="Permalink to &quot;Basic options&quot;">​</a></h3><p>Easy / Kodi centric distributions</p><ul><li><a href="https://kodi.wiki/view/LibreELEC" target="_blank" rel="noreferrer">LibreELEC</a> - <a href="https://libreelec.tv/downloads_new/" target="_blank" rel="noreferrer">Download</a> • <a href="https://wiki.libreelec.tv/" target="_blank" rel="noreferrer">Wiki</a> • <a href="http://forum.libreelec.tv/" target="_blank" rel="noreferrer">Forum</a></li><li><a href="https://kodi.wiki/view/OSMC" target="_blank" rel="noreferrer">OSMC</a> - <a href="https://osmc.tv/" target="_blank" rel="noreferrer">Home</a> <a href="https://osmc.tv/download/" target="_blank" rel="noreferrer">Installing</a> • <a href="https://osmc.tv/wiki" target="_blank" rel="noreferrer">Wiki</a> • <a href="https://discourse.osmc.tv/" target="_blank" rel="noreferrer">Support Forum</a></li></ul><br><p>Advanced / can be used with Kodi</p><ul><li>Arch Linux ARM - <a href="https://archlinuxarm.org/platforms/armv8/broadcom/raspberry-pi-4" target="_blank" rel="noreferrer">RPi4</a> • <a href="https://archlinuxarm.org/platforms/armv8/broadcom/raspberry-pi-3" target="_blank" rel="noreferrer">RPi3</a> • <a href="http://archlinuxarm.org/platforms/armv7/broadcom/raspberry-pi-2" target="_blank" rel="noreferrer">RPi2</a> • <a href="http://archlinuxarm.org/platforms/armv6/raspberry-pi" target="_blank" rel="noreferrer">RPi1</a></li></ul><p>Note that Arch ARM provides different Kodi packages optimized for different RPi models. All builds offer some flavor of HW accelerated decoding just like LibreELEC. The following packages will supply the current stable version of Kodi:</p><p><a href="https://github.com/archlinuxarm/PKGBUILDs/tree/master/alarm/kodi-rpi" target="_blank" rel="noreferrer">kodi-rpi</a> for RPi 3/4/400</p><p><a href="https://github.com/archlinuxarm/PKGBUILDs/tree/master/alarm/kodi-rpi-legacy" target="_blank" rel="noreferrer">kodi-rpi-legacy</a> for RPi 2</p><p>Users wanting to track the master branch may select:</p><p><a href="https://github.com/archlinuxarm/PKGBUILDs/tree/master/alarm/kodi-rpi" target="_blank" rel="noreferrer">kodi-rpi-git</a> for RPi 3/4/400 only</p><ul><li>Batocera Linux - <a href="https://batocera-linux.xorhub.com/#learn" target="_blank" rel="noreferrer">Learn More</a></li><li><a href="https://kodi.wiki/view/Buildroot" target="_blank" rel="noreferrer">Buildroot</a> - For experienced users only !</li></ul><br><ul><li>RetroPie - See <a href="https://kodi.wiki/view/HOW-TO:Install_Kodi_on_Raspberry_Pi#RetroPie" target="_blank" rel="noreferrer">full guide here</a></li></ul><h3 id="specific-install-guides" tabindex="-1">Specific install guides <a class="header-anchor" href="#specific-install-guides" aria-label="Permalink to &quot;Specific install guides&quot;">​</a></h3><p>For installs that don&#39;t directly include and/or boot into Kodi automatically.</p><h4 id="raspberry-pi-os" tabindex="-1">Raspberry Pi OS <a class="header-anchor" href="#raspberry-pi-os" aria-label="Permalink to &quot;Raspberry Pi OS&quot;">​</a></h4><p><a href="https://kodi.wiki/view/Template:Editor_note" target="_blank" rel="noreferrer"><em>Editor note</em></a><em>: We need to expand on this section, but here are the basic commands if you are familiar with the command-line:</em></p><p>(Current Version - 18.7)</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get update</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get install kodi</span></span></code></pre></div><br><p>PVR Addons</p><ul><li>PVR Addons can be installed directly from the command line:</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get update</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get install </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">PACKAGENAMEHERE</span></span></code></pre></div><p>but replace PACKAGENAMEHERE with the PVR addon required.</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">example: sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get install kodi</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pvr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hts</span></span></code></pre></div><p>The PVR client add-on should now be installed. If Kodi was already running, restart it to load the add-on.</p><h4 id="retropie" tabindex="-1">RetroPie <a class="header-anchor" href="#retropie" aria-label="Permalink to &quot;RetroPie&quot;">​</a></h4><p>Here&#39;s a <a href="https://www.youtube.com/watch?v=MyeCQS7ITnU" target="_blank" rel="noreferrer">youtube guide</a>:</p><h3 id="compiling-kodi" tabindex="-1">Compiling Kodi <a class="header-anchor" href="#compiling-kodi" aria-label="Permalink to &quot;Compiling Kodi&quot;">​</a></h3><p>Notes for advanced users who wish to try and build Kodi from source code.</p><ul><li>Various good notes mentioned here: <a href="https://github.com/xbmc/xbmc/blob/master/docs/README.RaspberryPi.md" target="_blank" rel="noreferrer">https://github.com/xbmc/xbmc/blob/master/docs/README.RaspberryPi.md</a></li></ul>`,40)])])}const b=i(s,[["render",o]]);export{c as __pageData,b as default};
